        <button id="btnRespot" class="btn-secondary">
          Re-spot Cue Ball
        </button>
      </div>
      <div class="status-text" id="statusDisplay">Ready to shoot</div>
    </div>

    <div class="instructions-card">
      <h3>Visible On-Screen Instructions</h3>
      <ul>
        <li>🎯 <span>Aim & Shoot:</span> Press on the white cue ball, drag <b>BACK</b> to adjust trajectory & power, then release to shoot.</li>
        <li>⚡ <span>Power:</span> Pulling further back increases shot velocity.</li>
        <li>🎱 <span>Objective:</span> Pot all object balls into any of the 6 pockets around the table.</li>
        <li>🔄 <span>Reset:</span> Click <b>Reset / Rack</b> to return balls to standard starting layout.</li>
      </ul>
    </div>
  </div>

  <script>
    (function() {
      const CANVAS_W = 800;
      const CANVAS_H = 400;
      const BALL_R = 12;
      const POCKET_R = 22;
      const FRICTION = 120; // Linear deceleration in px/sec^2
      const CUSHION_RESTITUTION = 0.98;
      const BALL_RESTITUTION = 0.99;

      const canvas = document.getElementById('billiardsCanvas');
      const ctx = canvas.getContext('2d');
      const btnReset = document.getElementById('btnReset');
      const btnRespot = document.getElementById('btnRespot');
      const statusDisplay = document.getElementById('statusDisplay');

      // 6 Pocket Centers
      const pockets = [
        { x: 0, y: 0 },
        { x: CANVAS_W / 2, y: 0 },
        { x: CANVAS_W, y: 0 },
        { x: 0, y: CANVAS_H },
        { x: CANVAS_W / 2, y: CANVAS_H },
        { x: CANVAS_W, y: CANVAS_H }
      ];

      // Interactive drag state
      let isDragging = false;
      let dragStart = { x: 0, y: 0 };
      let dragCurrent = { x: 0, y: 0 };

      // Simulation Object Definition
      const sim = {
        W: CANVAS_W,
        H: CANVAS_H,
        R: BALL_R,
        balls: [],
        running: true,
        animId: null,
        lastTimestamp: null,

        reset: function(ballsInput) {
          if (Array.isArray(ballsInput) && ballsInput.length > 0) {
            this.balls = ballsInput.map((b) => ({
              x: Number(b.x),
              y: Number(b.y),
              vx: Number(b.vx || 0),
              vy: Number(b.vy || 0),
              cue: Boolean(b.cue),
              potted: Boolean(b.potted)
            }));
          } else {
            this.balls = createDefaultRack();
          }
          draw();
        },

        step: function(dt) {
          if (dt > 0) {
            // Fixed small sub-step size for numerical stability & exact collision resolution
            const maxSubDt = 0.0005;
            const steps = Math.max(1, Math.ceil(dt / maxSubDt));
            const subDt = dt / steps;

            for (let s = 0; s < steps; s++) {
              updatePhysicsSubstep(subDt, this.balls, this.W, this.H, this.R);
            }
          }
          draw();
        },

        state: function() {
          return this.balls.map(b => ({
            x: b.x,
            y: b.y,
            vx: b.vx,
            vy: b.vy,
            potted: Boolean(b.potted),
            cue: Boolean(b.cue)
          }));
        },

        shoot: function(vx, vy) {
          const cueBall = this.balls.find(b => b.cue && !b.potted);
          if (cueBall) {
            cueBall.vx = Number(vx);
            cueBall.vy = Number(vy);
          }
        },

        pause: function() {
          this.running = false;
          if (this.animId) {
            cancelAnimationFrame(this.animId);
            this.animId = null;
          }
        },

        resume: function() {
          if (!this.running) {
            this.running = true;
            this.lastTimestamp = null;
            this.animId = requestAnimationFrame(gameLoop);
          }
        }
      };

      window.sim = sim;

      // Default 15-ball racked layout setup
      function createDefaultRack() {
        const balls = [];

        // Cue ball placed at head spot
        balls.push({
          x: CANVAS_W * 0.25,
          y: CANVAS_H * 0.5,
          vx: 0,
          vy: 0,
          cue: true,
          potted: false
        });

        // 15 Object balls in a triangle rack at foot spot
        const startX = CANVAS_W * 0.70;
        const startY = CANVAS_H * 0.5;
        const spacing = BALL_R * 2 + 0.5;
        const rowH = spacing * Math.sqrt(3) / 2;

        let ballIndex = 0;
        for (let r = 0; r < 5; r++) {
          const count = r + 1;
          const x = startX + r * rowH;
          const startRowY = startY - (count - 1) * spacing * 0.5;
          for (let c = 0; c < count; c++) {
            const y = startRowY + c * spacing;
            balls.push({
              x: x,
              y: y,
              vx: 0,
              vy: 0,
              cue: false,
              potted: false
            });
            ballIndex++;
          }
        }
        return balls;
      }

      // Single physics sub-step simulation
      function updatePhysicsSubstep(subDt, balls, W, H, R) {
        // 1. Position update & smooth linear friction deceleration
        for (let i = 0; i < balls.length; i++) {
          const b = balls[i];
          if (b.potted) continue;

          b.x += b.vx * subDt;
          b.y += b.vy * subDt;

          const speed = Math.hypot(b.vx, b.vy);
          if (speed > 0) {
            const newSpeed = Math.max(0, speed - FRICTION * subDt);
            const factor = newSpeed / speed;
            b.vx *= factor;
            b.vy *= factor;
          }
        }

        // 2. Pocket detection
        for (let i = 0; i < balls.length; i++) {
          const b = balls[i];
          if (b.potted) continue;

          for (let p = 0; p < pockets.length; p++) {
            const pk = pockets[p];
            const dist = Math.hypot(b.x - pk.x, b.y - pk.y);
            if (dist <= POCKET_R) {
              b.potted = true;
              b.vx = 0;
              b.vy = 0;
              b.x = pk.x;
              b.y = pk.y;
              break;
            }
          }
        }

        // 3. Cushion wall reflection
        for (let i = 0; i < balls.length; i++) {
          const b = balls[i];
          if (b.potted) continue;

          if (b.x < R) {
            b.x = R;
            b.vx = Math.abs(b.vx) * CUSHION_RESTITUTION;
          } else if (b.x > W - R) {
            b.x = W - R;
            b.vx = -Math.abs(b.vx) * CUSHION_RESTITUTION;
          }

          if (b.y < R) {
            b.y = R;
            b.vy = Math.abs(b.vy) * CUSHION_RESTITUTION;
          } else if (b.y > H - R) {
            b.y = H - R;
            b.vy = -Math.abs(b.vy) * CUSHION_RESTITUTION;
          }
        }

        // 4. Equal-mass ball-to-ball elastic collisions (2 solver passes for cluster stability)
        const len = balls.length;
        for (let pass = 0; pass < 2; pass++) {
          for (let i = 0; i < len; i++) {
            const b1 = balls[i];
            if (b1.potted) continue;

            for (let j = i + 1; j < len; j++) {
              const b2 = balls[j];
              if (b2.potted) continue;

              let dx = b2.x - b1.x;
              let dy = b2.y - b1.y;
              let dist = Math.hypot(dx, dy);
              const minDist = 2 * R;

              if (dist < minDist) {
                let nx, ny;
                if (dist === 0) {
                  nx = 1;
                  ny = 0;
                  dist = 0.001;
                } else {
                  nx = dx / dist;
                  ny = dy / dist;
                }

                // Positional overlap resolution
                const overlap = minDist - dist;
                b1.x -= nx * overlap * 0.5;
                b1.y -= ny * overlap * 0.5;
                b2.x += nx * overlap * 0.5;
                b2.y += ny * overlap * 0.5;

                // Impulse along normal vector
                const rvx = b1.vx - b2.vx;
                const rvy = b1.vy - b2.vy;
                const velAlongNormal = rvx * nx + rvy * ny;

                if (velAlongNormal > 0) {
                  const impulse = (1 + BALL_RESTITUTION) * velAlongNormal / 2;
                  b1.vx -= impulse * nx;
                  b1.vy -= impulse * ny;
                  b2.vx += impulse * nx;
                  b2.vy += impulse * ny;
                }
              }
            }
          }
        }
      }

      // Main visual rendering logic
      function draw() {
        ctx.clearRect(0, 0, CANVAS_W, CANVAS_H);

        // 1. Felt table background
        const feltGrad = ctx.createRadialGradient(CANVAS_W/2, CANVAS_H/2, 100, CANVAS_W/2, CANVAS_H/2, 500);
        feltGrad.addColorStop(0, '#0f7035');
        feltGrad.addColorStop(1, '#094520');
        ctx.fillStyle = feltGrad;
        ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

        // 2. Head string line & foot spot dot
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.15)';
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.moveTo(CANVAS_W * 0.25, 0);
        ctx.lineTo(CANVAS_W * 0.25, CANVAS_H);
        ctx.stroke();

        ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.beginPath();
        ctx.arc(CANVAS_W * 0.70, CANVAS_H * 0.5, 3, 0, Math.PI * 2);
        ctx.fill();

        // 3. Draw 6 Pocket Holes
        for (let p = 0; p < pockets.length; p++) {
          const pk = pockets[p];
          ctx.beginPath();
          ctx.arc(pk.x, pk.y, POCKET_R, 0, Math.PI * 2);
          const pGrad = ctx.createRadialGradient(pk.x, pk.y, 2, pk.x, pk.y, POCKET_R);
          pGrad.addColorStop(0, '#000000');
          pGrad.addColorStop(0.8, '#151515');
          pGrad.addColorStop(1, '#332211');
          ctx.fillStyle = pGrad;
          ctx.fill();

          ctx.strokeStyle = '#442b1d';
          ctx.lineWidth = 2;
          ctx.stroke();
        }

        // Color palette for object balls
        const ballColors = [
          '#f1c40f', '#2980b9', '#e74c3c', '#8e44ad', '#e67e22', '#27ae60', '#78281f',
          '#111111',
          '#f1c40f', '#2980b9', '#e74c3c', '#8e44ad', '#e67e22', '#27ae60', '#78281f'
        ];

        // 4. Render Balls
        for (let i = 0; i < sim.balls.length; i++) {
          const b = sim.balls[i];
          if (b.potted) continue;

          // Ball drop shadow
          ctx.beginPath();
          ctx.arc(b.x + 3, b.y + 3, BALL_R, 0, Math.PI * 2);
          ctx.fillStyle = 'rgba(0, 0, 0, 0.35)';
          ctx.fill();

          // Ball Base Color
          ctx.beginPath();
          ctx.arc(b.x, b.y, BALL_R, 0, Math.PI * 2);

          let baseColor = '#ffffff';
          if (!b.cue) {
            baseColor = ballColors[(i - 1) % ballColors.length];
          }
          ctx.fillStyle = baseColor;
          ctx.fill();

          // Stripe ball pattern (for balls #9-15)
          if (!b.cue && (i - 1) % 15 >= 8) {
            ctx.save();
            ctx.beginPath();
            ctx.arc(b.x, b.y, BALL_R, 0, Math.PI * 2);
            ctx.clip();

            ctx.fillStyle = '#ffffff';
            ctx.fillRect(b.x - BALL_R, b.y - BALL_R * 0.5, BALL_R * 2, BALL_R);
            ctx.restore();
          }

          // Ball number circle indicator
          if (!b.cue) {
            ctx.beginPath();
            ctx.arc(b.x, b.y, BALL_R * 0.45, 0, Math.PI * 2);
            ctx.fillStyle = '#ffffff';
            ctx.fill();

            ctx.fillStyle = '#000000';
            ctx.font = 'bold 8px sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillText(i.toString(), b.x, b.y + 0.5);
          }

          // Specular 3D Highlight Shine
          const shineGrad = ctx.createRadialGradient(
            b.x - BALL_R * 0.3, b.y - BALL_R * 0.3, 1,
            b.x, b.y, BALL_R
          );
          shineGrad.addColorStop(0, 'rgba(255, 255, 255, 0.65)');
          shineGrad.addColorStop(0.5, 'rgba(255, 255, 255, 0.0)');
          shineGrad.addColorStop(1, 'rgba(0, 0, 0, 0.25)');

          ctx.beginPath();
          ctx.arc(b.x, b.y, BALL_R, 0, Math.PI * 2);
          ctx.fillStyle = shineGrad;
          ctx.fill();
        }

        // 5. Cue Aiming & Power Drag Indicator
        if (isDragging) {
          const cueBall = sim.balls.find(b => b.cue && !b.potted);
          if (cueBall) {
            const dx = cueBall.x - dragCurrent.x;
            const dy = cueBall.y - dragCurrent.y;
            const dragDist = Math.hypot(dx, dy);

            if (dragDist > 3) {
              const angle = Math.atan2(dy, dx);

              // Draw aim trajectory line
              const aimLen = 300;
              ctx.save();
              ctx.beginPath();
              ctx.setLineDash([6, 6]);
              ctx.moveTo(cueBall.x, cueBall.y);
              ctx.lineTo(cueBall.x + Math.cos(angle) * aimLen, cueBall.y + Math.sin(angle) * aimLen);
              ctx.strokeStyle = 'rgba(255, 255, 255, 0.75)';
              ctx.lineWidth = 2;
              ctx.stroke();
              ctx.restore();

              // Draw cue stick graphic
              const cueOffset = BALL_R + 8 + dragDist * 0.4;
              const cueLen = 220;
              const stickBackX = cueBall.x - Math.cos(angle) * (cueOffset + cueLen);
              const stickBackY = cueBall.y - Math.sin(angle) * (cueOffset + cueLen);
              const stickFrontX = cueBall.x - Math.cos(angle) * cueOffset;
              const stickFrontY = cueBall.y - Math.sin(angle) * cueOffset;

              ctx.beginPath();
              ctx.moveTo(stickFrontX, stickFrontY);
              ctx.lineTo(stickBackX, stickBackY);
              ctx.strokeStyle = '#d97706';
              ctx.lineWidth = 5;
              ctx.lineCap = 'round';
              ctx.stroke();

              // Cue tip
              ctx.beginPath();
              ctx.moveTo(stickFrontX, stickFrontY);
              ctx.lineTo(stickFrontX - Math.cos(angle) * 6, stickFrontY - Math.sin(angle) * 6);
              ctx.strokeStyle = '#38bdf8';
              ctx.lineWidth = 4;
              ctx.stroke();
            }
          }
        }
      }

      // Animation Game Loop
      function gameLoop(timestamp) {
        if (!sim.running) return;

        if (sim.lastTimestamp === null) {
          sim.lastTimestamp = timestamp;
        }
        let dt = (timestamp - sim.lastTimestamp) / 1000;
        sim.lastTimestamp = timestamp;

        // Clamp dt to avoid huge step jumps if tab unfocused
        if (dt > 0.1) dt = 0.016;
        if (dt < 0) dt = 0;

        sim.step(dt);
        updateStatusText();

        sim.animId = requestAnimationFrame(gameLoop);
      }

      // Helpers
      function areBallsMoving() {
        return sim.balls.some(b => !b.potted && Math.hypot(b.vx, b.vy) > 1);
      }

      function updateStatusText() {
        const cueBall = sim.balls.find(b => b.cue);
        if (cueBall && cueBall.potted) {
          statusDisplay.textContent = "Cue ball potted (Scratch)! Click 'Re-spot Cue Ball'";
          statusDisplay.style.color = '#ef4444';
        } else if (areBallsMoving()) {
          statusDisplay.textContent = "Balls in motion...";
          statusDisplay.style.color = '#eab308';
        } else {
          statusDisplay.textContent = "Ready to shoot";
          statusDisplay.style.color = '#cbd5e1';
        }
      }

      function getPointerPos(e) {
        const rect = canvas.getBoundingClientRect();
        let clientX = e.clientX;
        let clientY = e.clientY;
        if (e.touches && e.touches.length > 0) {
          clientX = e.touches[0].clientX;
          clientY = e.touches[0].clientY;
        }
        return {
          x: (clientX - rect.left) * (CANVAS_W / rect.width),
          y: (clientY - rect.top) * (CANVAS_H / rect.height)
        };
      }

      // Pointer Event Handlers
      function handleStart(e) {
        const pos = getPointerPos(e);
        const cueBall = sim.balls.find(b => b.cue && !b.potted);

        if (cueBall && !areBallsMoving()) {
          const dist = Math.hypot(pos.x - cueBall.x, pos.y - cueBall.y);
          if (dist <= BALL_R * 3.5) {
            isDragging = true;
            dragStart = { x: cueBall.x, y: cueBall.y };
            dragCurrent = pos;
            e.preventDefault();
          }
        }
      }

      function handleMove(e) {
        if (isDragging) {
          dragCurrent = getPointerPos(e);
          draw();
          e.preventDefault();
        }
      }

      function handleEnd(e) {
        if (isDragging) {
          const cueBall = sim.balls.find(b => b.cue && !b.potted);
          if (cueBall) {
            const dx = cueBall.x - dragCurrent.x;
            const dy = cueBall.y - dragCurrent.y;
            const dragDist = Math.hypot(dx, dy);

            if (dragDist > 5) {
              const powerScale = 7.5;
              let vx = dx * powerScale;
              let vy = dy * powerScale;

              // Cap max shot speed
              const speed = Math.hypot(vx, vy);
              const maxSpeed = 2200;
              if (speed > maxSpeed) {
                vx = (vx / speed) * maxSpeed;
                vy = (vy / speed) * maxSpeed;
              }

              sim.shoot(vx, vy);
            }
          }
          isDragging = false;
          draw();
        }
      }

      // Mouse Listener Binding
      canvas.addEventListener('mousedown', handleStart);
      window.addEventListener('mousemove', handleMove);
      window.addEventListener('mouseup', handleEnd);

      // Touch Listener Binding
      canvas.addEventListener('touchstart', handleStart, { passive: false });
      window.addEventListener('touchmove', handleMove, { passive: false });
      window.addEventListener('touchend', handleEnd);

      // UI Button Controls
      btnReset.addEventListener('click', () => {
        sim.reset();
      });

      btnRespot.addEventListener('click', () => {
        let cueBall = sim.balls.find(b => b.cue);
        if (cueBall) {
          cueBall.potted = false;
          cueBall.x = CANVAS_W * 0.25;
          cueBall.y = CANVAS_H * 0.5;
          cueBall.vx = 0;
          cueBall.vy = 0;
        } else {
          sim.balls.push({
            x: CANVAS_W * 0.25,
            y: CANVAS_H * 0.5,
            vx: 0,
            vy: 0,
            cue: true,
            potted: false
          });
        }
        draw();
        updateStatusText();
      });

      // Initial state reset & start main loop
      sim.reset();
      sim.resume();

    })();
  </script>
</body>
